const candidates = JSON.parse(inputData.pooled_candidates_json || '[]');
const roles = JSON.parse(inputData.new_roles_json || '[]');
const matches = [];
for (const candidate of candidates) {
  const cSkills = (candidate.skills || '').toLowerCase().split(',').map(s => s.trim()).filter(Boolean);
  for (const role of roles) {
    const rSkills = (role.required_skills || '').toLowerCase().split(',').map(s => s.trim()).filter(Boolean);
    if (rSkills.length === 0) continue;
    let count = 0;
    for (const rs of rSkills) {
      if (cSkills.some(cs => cs.includes(rs) || rs.includes(cs))) count++;
    }
    const score = Math.round((count / rSkills.length) * 100);
    if (score >= 40) {
      matches.push({
        candidate_name: candidate.name,
        candidate_email: candidate.email,
        role_title: role.role_title,
        match_score: score,
        candidate_record_id: candidate.id,
        role_record_id: role.id
      });
    }
  }
}
matches.sort((a, b) => b.match_score - a.match_score);
const lines = matches.slice(0, 10).map(m =>
  `• *${m.candidate_name}* → *${m.role_title}* (${m.match_score}% match) — ${m.candidate_email}`
).join('\n');
return {
  match_count: matches.length,
  digest_lines: lines || 'No new matches found.',
  has_matches: matches.length > 0 ? 'true' : 'false'
};

